import React, { useEffect, useState } from "react";
import axios from "axios";

function MyPredictionHistory() {
  const [history, setHistory] = useState([]);

  const user = JSON.parse(localStorage.getItem("user"));

  useEffect(() => {
    if (user?.email) {
      axios
        .get(`http://localhost:5000/history/${user.email}`)
        .then((res) => {
          console.log("HISTORY DATA 👉", res.data); // 🔥 DEBUG
          setHistory(res.data);
        })
        .catch((err) => console.log(err));
    }
  }, [user]);

  return (
    <div style={{ padding: "30px" }}>
      <h2>My Prediction History</h2>

      <p>Total Predictions: {history.length}</p>

      <table border="1" cellPadding="10">
        <thead>
          <tr>
            <th>Date & Time</th>
            <th>Role</th>
            <th>Experience</th>
            <th>Salary</th>
          </tr>
        </thead>

        <tbody>
          {history.length > 0 ? (
            history.map((item, index) => (
              <tr key={index}>
                <td>
                  {new Date(item.createdAt).toLocaleString()}
                </td>
                <td>{item.JobRole}</td>
                <td>{item.Experience} yrs</td>
                <td>₹ {item.salary}</td>
              </tr>
            ))
          ) : (
            <tr>
              <td colSpan="4">No history found</td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
}

export default MyPredictionHistory;
